1	// Edge function: decide-application (US-057)
2	//
3	// Contract:
4	//   POST { application_id: string,
5	//          action: 'approve' | 'reject',
6	//          decision_note?: string,
7	//          override_ineligible?: boolean }
8	//     → 200 { ok: true, status: 'approved' | 'rejected', decided_at: string }
9	//     → 200 { ok: false, drift: Array<{metric, platform, required, actual}> }
10	//             // approve path only — creator no longer meets pre-conditions;
11	//             // client opens the override confirmation dialog.
12	//     → 400 { error: 'INVALID_JSON' | 'INVALID_REQUEST' }
13	//     → 401 { error: 'UNAUTHORIZED' }
14	//     → 403 { error: 'FORBIDDEN' }                    // non-lister role
15	//     → 404 { error: 'APPLICATION_NOT_FOUND' }
16	//     → 403 { error: 'NOT_OWNER' }                    // not this lister's listing
17	//     → 409 { error: 'NOT_PENDING' }                  // already decided / withdrawn / cancelled
18	//     → 409 { error: 'LISTING_VERSION_CHANGED',
19	//             current_version_id: string }            // version raced; client re-opens
20	//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' }
21	//
22	// Auth: Marketify JWT (HS256, MARKETIFY_JWT_SECRET). Verifies via
23	//       _shared/jwt.ts and asserts role='lister'. Deployed with
24	//       verify_jwt=false at the gateway because the gateway only knows
25	//       about Supabase's own JWT secret — the handler enforces auth.
26	//
27	// Concurrency / version pin — same pattern as US-041's apply-to-listing
28	// (Codebase Pattern #105). For a non-override approve, we re-run pre-
29	// conditions in TS against the listing's CURRENT current_version_id, then
30	// hand that version to the RPC as `p_expected_version_id`. The RPC takes
31	// SELECT ... FOR UPDATE on the application row and re-reads
32	// listings.current_version_id — if a fresh `app_private.bump_listing_version`
33	// interleaved, the RPC returns LISTING_VERSION_CHANGED and the client
34	// reloads the review sheet.
35	//
36	// Override path (§4.6 OverrideEligibilityDialog) — when
37	// `override_ineligible=true`, we skip eligibility AND skip the version pin.
38	// Override is a deliberate force-approve: the lister has accepted the
39	// drift, so a freshly bumped version doesn't change their decision. We
40	// pass `p_expected_version_id=null` to the RPC.
41	//
42	// Drift response shape — `{ok:false, drift:[...]}` is intentionally NOT
43	// an HTTP error. The approve action succeeded "as a check"; the client
44	// uses the returned drift to render the override confirmation dialog and
45	// re-POST with `override_ineligible:true`. Per US-057 AC: "approve runs
46	// a NEW edge function ... returns {ok:true} or {ok:false, drift:string[]}".
47	// We return rich `FailedCondition` objects (same shape as apply-to-listing's
48	// `failed_conditions`) rather than opaque strings so the dialog can render
49	// "min_followers (tiktok): need 10000, have 7400" instead of a bare string.
50	//
51	// Reject path — never re-runs eligibility, never checks the version pin
52	// (rejecting a no-longer-eligible creator is always allowed and not a
53	// drift signal). `decision_note` is optional but persisted.
54	
55	import { createClient } from "npm:@supabase/supabase-js@2";
56	import { verifyJwt } from "../_shared/jwt.ts";
57	import { corsHeaders } from "../_shared/cors.ts";
58	import {
59	  type ConditionRow,
60	  type CreatorProfileRow,
61	  EMPTY_CREATOR_METRICS,
62	  evaluatePreConditions,
63	} from "../_shared/eligibility.ts";
64	
65	const UUID_RE =
66	  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
67	
68	// Same cap as apply-to-listing's cover_note. decision_note is the lister-
69	// authored explanation surfaced in notifications + applications row history.
70	const DECISION_NOTE_MAX_LEN = 2000;
71	
72	interface DecideRequest {
73	  application_id?: unknown;
74	  action?: unknown;
75	  decision_note?: unknown;
76	  override_ineligible?: unknown;
77	}
78	
79	function jsonResponse(status: number, body: unknown): Response {
80	  return new Response(JSON.stringify(body), {
81	    status,
82	    headers: { ...corsHeaders, "Content-Type": "application/json" },
83	  });
84	}
85	
86	function bearerToken(req: Request): string | null {
87	  const raw = req.headers.get("Authorization") ??
88	    req.headers.get("authorization");
89	  if (!raw) return null;
90	  const m = raw.match(/^Bearer\s+(.+)$/i);
91	  return m ? m[1].trim() : null;
92	}
93	
94	Deno.serve(async (req) => {
95	  if (req.method === "OPTIONS") {
96	    return new Response(null, { status: 204, headers: corsHeaders });
97	  }
98	  if (req.method !== "POST") {
99	    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
100	  }
101	
102	  const token = bearerToken(req);
103	  if (!token) return jsonResponse(401, { error: "UNAUTHORIZED" });
104	
105	  let claims;
106	  try {
107	    claims = await verifyJwt(token);
108	  } catch {
109	    return jsonResponse(401, { error: "UNAUTHORIZED" });
110	  }
111	  if (claims.app_role !== "lister") {
112	    return jsonResponse(403, { error: "FORBIDDEN" });
113	  }
114	
115	  let body: DecideRequest;
116	  try {
117	    body = await req.json();
118	  } catch {
119	    return jsonResponse(400, { error: "INVALID_JSON" });
120	  }
121	
122	  const applicationId =
123	    typeof body.application_id === "string" && UUID_RE.test(body.application_id)
124	      ? body.application_id
125	      : null;
126	  if (!applicationId) {
127	    return jsonResponse(400, { error: "INVALID_REQUEST" });
128	  }
129	
130	  const action = body.action === "approve" || body.action === "reject"
131	    ? body.action
132	    : null;
133	  if (!action) {
134	    return jsonResponse(400, { error: "INVALID_REQUEST" });
135	  }
136	
137	  const overrideIneligible = body.override_ineligible === true;
138	  // Override is meaningless on a reject — silently ignore rather than 400
139	  // so a UI that always sets it can't accidentally lock out a reject.
140	  const effectiveOverride = action === "approve" && overrideIneligible;
141	
142	  let decisionNote: string | null = null;
143	  if (body.decision_note !== undefined && body.decision_note !== null) {
144	    if (typeof body.decision_note !== "string") {
145	      return jsonResponse(400, { error: "INVALID_REQUEST" });
146	    }
147	    const trimmed = body.decision_note.trim();
148	    if (trimmed.length > DECISION_NOTE_MAX_LEN) {
149	      return jsonResponse(400, { error: "INVALID_REQUEST" });
150	    }
151	    decisionNote = trimmed.length > 0 ? trimmed : null;
152	  }
153	
154	  const supabaseUrl = Deno.env.get("SUPABASE_URL");
155	  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
156	  if (!supabaseUrl || !serviceRoleKey) {
157	    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
158	  }
159	
160	  const supabase = createClient(supabaseUrl, serviceRoleKey, {
161	    auth: { persistSession: false, autoRefreshToken: false },
162	  });
163	
164	  // Fetch the application + its listing in one round trip so we can check
165	  // ownership, current status, and resolve the listing's version BEFORE
166	  // running eligibility. We re-check all of this inside the RPC under a
167	  // row lock — these client-side checks are for early-return and to know
168	  // which version to evaluate against.
169	  const { data: appRow, error: appErr } = await supabase
170	    .from("applications")
171	    .select("id,status,creator_id,listing_id")
172	    .eq("id", applicationId)
173	    .maybeSingle();
174	
175	  if (appErr) {
176	    console.error("applications lookup failed", appErr);
177	    return jsonResponse(500, { error: "DB_ERROR" });
178	  }
179	  if (!appRow) {
180	    return jsonResponse(404, { error: "APPLICATION_NOT_FOUND" });
181	  }
182	  if (appRow.status !== "pending") {
183	    return jsonResponse(409, { error: "NOT_PENDING" });
184	  }
185	
186	  const { data: listing, error: listingErr } = await supabase
187	    .from("listings")
188	    .select("id,lister_id,current_version_id")
189	    .eq("id", appRow.listing_id)
190	    .maybeSingle();
191	
192	  if (listingErr) {
193	    console.error("listings lookup failed", listingErr);
194	    return jsonResponse(500, { error: "DB_ERROR" });
195	  }
196	  if (!listing) {
197	    // Listing FK is on delete restrict so this should be unreachable.
198	    return jsonResponse(500, { error: "DB_ERROR" });
199	  }
200	  if (listing.lister_id !== claims.sub) {
201	    return jsonResponse(403, { error: "NOT_OWNER" });
202	  }
203	
204	  const versionId = listing.current_version_id as string | null;
205	  if (!versionId) {
206	    console.error("listing missing current_version_id", listing.id);
207	    return jsonResponse(500, { error: "DB_ERROR" });
208	  }
209	
210	  // Approve path eligibility re-check. Skipped on override (§4.6) and on
211	  // reject (rejecting an ineligible creator is always allowed).
212	  if (action === "approve" && !effectiveOverride) {
213	    const [conditionsRes, profileRes] = await Promise.all([
214	      supabase
215	        .from("listing_conditions")
216	        .select("*")
217	        .eq("listing_version_id", versionId),
218	      supabase
219	        .from("creator_profiles")
220	        .select(
221	          "tiktok_follower_count,tiktok_avg_views_last_10,tiktok_total_likes," +
222	            "tiktok_video_count,tiktok_is_verified,instagram_follower_count," +
223	            "instagram_avg_views_last_10,instagram_media_count",
224	        )
225	        .eq("user_id", appRow.creator_id)
226	        .maybeSingle(),
227	    ]);
228	
229	    if (conditionsRes.error) {
230	      console.error("listing_conditions lookup failed", conditionsRes.error);
231	      return jsonResponse(500, { error: "DB_ERROR" });
232	    }
233	    if (profileRes.error) {
234	      console.error("creator_profiles lookup failed", profileRes.error);
235	      return jsonResponse(500, { error: "DB_ERROR" });
236	    }
237	
238	    const conditions = (conditionsRes.data ?? []) as ConditionRow[];
239	    const metrics: CreatorProfileRow = profileRes.data ?? EMPTY_CREATOR_METRICS;
240	    const drift = evaluatePreConditions(conditions, metrics);
241	    if (drift.length > 0) {
242	      // ok:false signals the client to render the override confirmation
243	      // dialog. This is NOT an HTTP error — the request itself succeeded
244	      // as a pre-flight eligibility probe.
245	      return jsonResponse(200, { ok: false, drift });
246	    }
247	  }
248	
249	  const { data: rpcData, error: rpcError } = await supabase.rpc(
250	    "decide_application_rpc",
251	    {
252	      p_application_id: applicationId,
253	      p_lister_id: claims.sub,
254	      p_action: action,
255	      p_decision_note: decisionNote,
256	      // Reject and override paths skip the pin (null = "don't check version").
257	      p_expected_version_id: action === "approve" && !effectiveOverride
258	        ? versionId
259	        : null,
260	    },
261	  );
262	
263	  if (rpcError) {
264	    console.error("decide_application_rpc error", rpcError);
265	    return jsonResponse(500, { error: "DB_ERROR" });
266	  }
267	
268	  const result = rpcData as
269	    | {
270	      ok?: boolean;
271	      status?: string;
272	      decided_at?: string;
273	      error?: string;
274	      current_version_id?: string;
275	    }
276	    | null;
277	
278	  if (result?.error === "APPLICATION_NOT_FOUND") {
279	    return jsonResponse(404, { error: "APPLICATION_NOT_FOUND" });
280	  }
281	  if (result?.error === "NOT_OWNER") {
282	    return jsonResponse(403, { error: "NOT_OWNER" });
283	  }
284	  if (result?.error === "NOT_PENDING") {
285	    return jsonResponse(409, { error: "NOT_PENDING" });
286	  }
287	  if (result?.error === "INVALID_ACTION") {
288	    return jsonResponse(400, { error: "INVALID_REQUEST" });
289	  }
290	  if (result?.error === "LISTING_VERSION_CHANGED") {
291	    return jsonResponse(409, {
292	      error: "LISTING_VERSION_CHANGED",
293	      current_version_id: result.current_version_id,
294	    });
295	  }
296	
297	  if (!result?.ok || !result.status || !result.decided_at) {
298	    console.error("decide_application_rpc returned unexpected shape", result);
299	    return jsonResponse(500, { error: "DB_ERROR" });
300	  }
301	
302	  return jsonResponse(200, {
303	    ok: true,
304	    status: result.status,
305	    decided_at: result.decided_at,
306	  });
307	});
