1	import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
2	import {
3	  Keyboard,
4	  Modal,
5	  Platform,
6	  Pressable,
7	  RefreshControl,
8	  SafeAreaView,
9	  ScrollView,
10	  StyleSheet,
11	  Text,
12	  TextInput,
13	  View,
14	} from 'react-native';
15	import { BottomSheet } from '@/components/primitives/BottomSheet';
16	import { ButtonPrimary, ButtonSecondary } from '@/components/primitives/Button';
17	import { StatusPill, type StatusPillStatus } from '@/components/primitives/StatusPill';
18	import { SkeletonCard } from '@/components/primitives/SkeletonCard';
19	import { useToast } from '@/components/primitives/Toast';
20	import { colors, radii, shadows, spacing } from '@/design/tokens';
21	import { fontFamilies, textStyles } from '@/design/typography';
22	import { useAuth } from '@/lib/auth';
23	import { getCachedToken } from '@/lib/storage';
24	import { supabase } from '@/lib/supabase';
25	import { formatRelativeTime } from '@/lib/time';
26	import type { Database } from '@/types/supabase';
27	
28	// US-056 — Lister Inbox, Applications sub-tab. Calls the
29	// `list_my_applications_as_lister` SECURITY DEFINER RPC (companion migration
30	// `us_056_list_my_applications_as_lister_rpc`) which joins applications →
31	// listings → users → creator_profiles → social_links under an explicit
32	// `listings.lister_id = current_user_id()` ownership gate and returns one
33	// flat row per application — creator username + platform handles + follower
34	// counts + IG avg views + pitch preview. Same list-my-rows pattern as
35	// US-043 / US-054 (Codebase Pattern #118).
36	//
37	// Segments: Pending / Approved / Rejected per AC. The RPC already excludes
38	// withdrawn + cancelled_listing_edit + cancelled_listing_closed — those are
39	// creator-initiated or cascade-driven cancellations that don't require
40	// lister review. They surface on the campaign-scoped detail screen
41	// (US-057+), not the inbox.
42	//
43	// Grouping: per docs/design.md §3.2 the inbox groups rows by campaign with
44	// inline SectionHeader separators. The RPC returns rows in
45	// `created_at desc`, so within each group rows remain recency-ordered; the
46	// group order is driven by the most-recent application within each group.
47	//
48	// Realtime INSERT subscription: applications is already in the
49	// supabase_realtime publication (US-044). We subscribe with no client
50	// filter because applications has no lister_id column — the
51	// `applications_lister_read` RLS policy is the join-through-listings
52	// security boundary (Codebase Pattern #123). Because the raw INSERT
53	// payload lacks the joined creator + platform metrics, on each insert we
54	// re-run the RPC rather than patching locally. A toast ("New application
55	// received", info variant) gives the lister an in-app cue.
56	//
57	// US-057 — pending rows are tappable; tap opens a ReviewApplicationSheet
58	// (bottom sheet, design.md §3.3). The sheet shows full creator metrics +
59	// pitch and exposes an optional "Note" field plus Approve / Reject
60	// buttons. Both buttons POST to the `decide-application` edge function.
61	//
62	// Approve flow:
63	//   1. POST { action:'approve', application_id, decision_note? }
64	//   2a. 200 {ok:true} → toast "Application approved", refresh list, close
65	//   2b. 200 {ok:false, drift:[...]} → close the review sheet and open the
66	//       OverrideEligibilityDialog (centered modal, design.md §5.2 — "modals
67	//       except confirmations are bottom sheets" + Codebase Pattern #129).
68	//   2c. Override "Approve anyway" → POST again with override_ineligible:true,
69	//       which skips eligibility AND skips the version pin per the
70	//       force-approve semantics in the RPC's docblock.
71	//
72	// Reject flow:
73	//   1. POST { action:'reject', application_id, decision_note? }
74	//   2. Toast "Application rejected", refresh list, close.
75	//
76	// LISTING_VERSION_CHANGED — surfaces a "Listing was updated" toast and
77	// re-loads. Same backstop as the creator-side ApplySheet.
78	
79	type ApplicationStatus = Database['public']['Enums']['application_status'];
80	type Segment = 'pending' | 'approved' | 'rejected';
81	type Row = Database['public']['Functions']['list_my_applications_as_lister']['Returns'][number];
82	
83	// Compile-time exhaustive mapping: if a new enum value is added the
84	// compiler flags the missing bucket (Codebase Pattern #121). The three
85	// enum values the RPC filters out are intentionally absent — they cannot
86	// reach this screen.
87	const STATUS_BUCKET: Record<
88	  Exclude<
89	    ApplicationStatus,
90	    'withdrawn' | 'cancelled_listing_edit' | 'cancelled_listing_closed'
91	  >,
92	  Segment
93	> = {
94	  pending: 'pending',
95	  approved: 'approved',
96	  rejected: 'rejected',
97	};
98	
99	const SEGMENTS: readonly { key: Segment; label: string }[] = [
100	  { key: 'pending', label: 'Pending' },
101	  { key: 'approved', label: 'Approved' },
102	  { key: 'rejected', label: 'Rejected' },
103	];
104	
105	type SegmentControlProps = {
106	  active: Segment;
107	  counts: Record<Segment, number>;
108	  onChange: (next: Segment) => void;
109	};
110	
111	function SegmentControl({ active, counts, onChange }: SegmentControlProps) {
112	  return (
113	    <View style={styles.segmentRow} accessibilityRole="tablist">
114	      {SEGMENTS.map((s) => (
115	        <SegmentButton
116	          key={s.key}
117	          label={`${s.label} (${counts[s.key]})`}
118	          selected={active === s.key}
119	          onPress={() => onChange(s.key)}
120	          testID={`segment-${s.key}`}
121	        />
122	      ))}
123	    </View>
124	  );
125	}
126	
127	type SegmentButtonProps = {
128	  label: string;
129	  selected: boolean;
130	  onPress: () => void;
131	  testID?: string;
132	};
133	
134	function SegmentButton({ label, selected, onPress, testID }: SegmentButtonProps) {
135	  const bg = selected ? colors.primarySoft : colors.surface;
136	  const textColor = selected ? colors.primaryDeep : colors.ink;
137	  return (
138	    <Pressable
139	      onPress={onPress}
140	      accessibilityRole="tab"
141	      accessibilityState={{ selected }}
142	      accessibilityLabel={label}
